css:
.sewing-consumption-print { font-size: 12px; color: #111; }
.sewing-consumption-print h2,
.sewing-consumption-print h3 { margin: 8px 0 6px; }
.sewing-consumption-print .title { text-align: center; font-size: 22px; font-weight: 700; margin-bottom: 18px; }
.sewing-consumption-print .meta-wrap { margin-bottom: 14px; }
.sewing-consumption-print .meta-table {
    width: 100%;
    border-collapse: collapse;
    table-layout: fixed;
}
.sewing-consumption-print .meta-table td {
    border: none;
    padding: 0;
    vertical-align: top;
}
.sewing-consumption-print .meta-half {
    width: 50%;
    padding-right: 12px;
}
.sewing-consumption-print .meta-half-right {
    width: 50%;
    padding-left: 12px;
}
.sewing-consumption-print .meta-inner {
    width: 100%;
    border-collapse: collapse;
    table-layout: fixed;
}
.sewing-consumption-print .meta-inner col.meta-col-label { width: 34%; }
.sewing-consumption-print .meta-inner col.meta-col-value { width: 66%; }
.sewing-consumption-print .meta-inner td {
    border: none;
    padding: 4px 0;
    vertical-align: baseline;
}
.sewing-consumption-print .meta-label {
    font-weight: 700;
    white-space: nowrap;
    padding-right: 8px;
}
.sewing-consumption-print .meta-value,
.sewing-consumption-print .meta-line {
    border-bottom: 1px solid #111;
    height: 18px;
    padding-bottom: 2px;
    white-space: nowrap;
    overflow: hidden;
}
.sewing-consumption-print .meta-value {
    width: 100%;
}
.sewing-consumption-print .meta-line {
    width: 100%;
}
.sewing-consumption-print table { width: 100%; border-collapse: collapse; margin-bottom: 14px; }
.sewing-consumption-print th,
.sewing-consumption-print td { border: 1px solid #111; padding: 4px 6px; vertical-align: top; }
.sewing-consumption-print th { background: #f2f2f2; }
.sewing-consumption-print .sign-row {
    display: flex;
    justify-content: space-between;
    margin-top: 70px;
    gap: 30px;
}
.sewing-consumption-print .sign-block {
    width: 42%;
    text-align: center;
}
.sewing-consumption-print .sign-line {
    border-top: 1px solid #111;
    height: 0;
    margin-bottom: 8px;
}
